import 'package:flutter_fractals/core/models/fractal_view_state.dart';

FractalPreset _makePreset(String id, String moduleId, {String name = 'Test', bool isBuiltIn = false}) {
  return FractalPreset(
    id: id,
    moduleId: moduleId,
    name: name,
    params: {'iterations': 100},
    view: FractalViewState(
      pan: Vector2(0.0, 0.0),
      zoom: 1.0,
      rotation: Vector3.zero(),
    ),
    createdAt: DateTime.utc(2024, 1, 1),
    isBuiltIn: isBuiltIn,
  );
}

void main() {
  group('PresetStore', () {
    setUp(() {
      TestWidgetsFlutterBinding.ensureInitialized();
      SharedPreferences.setMockInitialValues({});
    });

    test('create() factory returns a valid store', () async {
      final store = await PresetStore.create();
      expect(store, isNotNull);
    });

    test('loadUserPresets returns empty list for unknown module', () async {
      final store = await PresetStore.create();
      final presets = await store.loadUserPresets('unknown_module');
      expect(presets, isEmpty);
    });

    test('saveUserPreset persists preset and loadUserPresets returns it', () async {
      final store = await PresetStore.create();
      final preset = _makePreset('p1', 'mandelbrot', name: 'My Preset');

      await store.saveUserPreset(preset);
      final loaded = await store.loadUserPresets('mandelbrot');

      expect(loaded, hasLength(1));
      expect(loaded.first.id, equals('p1'));
      expect(loaded.first.name, equals('My Preset'));
      expect(loaded.first.moduleId, equals('mandelbrot'));
    });

    test('loadUserPresets for a different module returns empty list', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot'));

      final loaded = await store.loadUserPresets('julia');
      expect(loaded, isEmpty);
    });

    test('deleteUserPreset removes the preset', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot'));
      await store.saveUserPreset(_makePreset('p2', 'mandelbrot'));

      await store.deleteUserPreset('mandelbrot', 'p1');
      final loaded = await store.loadUserPresets('mandelbrot');

      expect(loaded, hasLength(1));
      expect(loaded.first.id, equals('p2'));
    });

    test('deleteUserPreset on non-existent id leaves list unchanged', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot'));

      await store.deleteUserPreset('mandelbrot', 'does-not-exist');
      final loaded = await store.loadUserPresets('mandelbrot');

      expect(loaded, hasLength(1));
    });

    test('saveUserPreset replaces preset with same id', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot', name: 'Original'));
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot', name: 'Updated'));

      final loaded = await store.loadUserPresets('mandelbrot');
      expect(loaded, hasLength(1));
      expect(loaded.first.name, equals('Updated'));
    });

    test('user presets are stored separately per module', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot'));
      await store.saveUserPreset(_makePreset('p2', 'julia'));

      final mandelbrot = await store.loadUserPresets('mandelbrot');
      final julia = await store.loadUserPresets('julia');

      expect(mandelbrot, hasLength(1));
      expect(mandelbrot.first.id, equals('p1'));
      expect(julia, hasLength(1));
      expect(julia.first.id, equals('p2'));
    });

    test('user presets are separate from built-in presets (isBuiltIn flag preserved)', () async {
      final store = await PresetStore.create();
      final userPreset = _makePreset('user-1', 'mandelbrot', isBuiltIn: false);
      final builtIn = _makePreset('builtin-1', 'mandelbrot', isBuiltIn: true);

      await store.saveUserPreset(userPreset);
      await store.saveUserPreset(builtIn);

      final loaded = await store.loadUserPresets('mandelbrot');
      expect(loaded, hasLength(2));

      final userLoaded = loaded.firstWhere((p) => p.id == 'user-1');
      final builtInLoaded = loaded.firstWhere((p) => p.id == 'builtin-1');
      expect(userLoaded.isBuiltIn, isFalse);
      expect(builtInLoaded.isBuiltIn, isTrue);
    });

    test('updatePreset renames preset by id', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot', name: 'Old Name'));

      await store.updatePreset('mandelbrot', 'p1', name: 'New Name');
      final loaded = await store.loadUserPresets('mandelbrot');

      expect(loaded.first.name, equals('New Name'));
    });

    test('updatePreset on non-existent id is a no-op', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot', name: 'Original'));

      await store.updatePreset('mandelbrot', 'does-not-exist', name: 'Ghost');
      final loaded = await store.loadUserPresets('mandelbrot');

      expect(loaded.first.name, equals('Original'));
    });
  });
}

import 'dart:convert';

import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:flutter_fractals/core/models/fractal_palette.dart';

class PaletteStore {
  static const _key = 'user_palettes_v1';

  final SharedPreferences _prefs;

  PaletteStore._(this._prefs);

  static Future<PaletteStore> create() async {
    final prefs = await SharedPreferences.getInstance();
    return PaletteStore._(prefs);
  }

  List<FractalPalette> loadPalettes() {
    final list = _prefs.getStringList(_key);
    if (list != null) return _decodePaletteStringList(list);

    return _decodeLegacyPaletteArray(_prefs.getString(_key));
  }

  List<FractalPalette> _decodePaletteStringList(List<String> encodedPalettes) {
    final palettes = <FractalPalette>[];
    for (final encoded in encodedPalettes) {
      final palette = _tryDecodePaletteString(encoded);
      if (palette != null && palette.id.isNotEmpty) palettes.add(palette);
    }
    return palettes;
  }

  FractalPalette? _tryDecodePaletteString(String encoded) {
    try {
      return FractalPalette.fromJsonString(encoded);
    } catch (e) {
      if (kDebugMode) debugPrint('[FF] skipping palette entry: $e');
      return null;
    }
  }

  List<FractalPalette> _decodeLegacyPaletteArray(String? payload) {
    if (payload == null || payload.trim().isEmpty) return const [];

    try {
      final decodedArr = (jsonDecode(payload) as List).cast<Map>();
      return decodedArr
          .map((m) => FractalPalette.fromJson(m.cast<String, Object?>()))
          .where((p) => p.id.isNotEmpty)
          .toList();
    } catch (e) {
      if (kDebugMode) debugPrint('[FF] silent catch: $e');
      return const [];
    }
  }

  Future<void> savePalettes(List<FractalPalette> palettes) async {
    final list = palettes.map((p) => p.toJsonString(pretty: false)).toList();
    await _prefs.setStringList(_key, list);
  }
}

import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';

/// Persists exploration history and favorites to local storage.
///
/// History entries are stored in SharedPreferences as JSON.
/// Maintains separate storage for:
/// - Navigation history (limited size, auto-trimmed)
/// - Favorites (unlimited, user-managed)
///
/// {@category Services}
class HistoryStore {
  final SharedPreferences _prefs;

  static const String _historyKey = 'exploration_history';
  static const String _favoritesKey = 'exploration_favorites';
  static const int maxHistoryEntries = 100;
  static const int maxFavoriteEntries = 500;

  HistoryStore._(this._prefs);

  /// Creates a new [HistoryStore] instance.
  static Future<HistoryStore> create() async {
    final prefs = await SharedPreferences.getInstance();
    return HistoryStore._(prefs);
  }

  /// Loads the navigation history.
  ///
  /// Returns entries in chronological order (oldest first).
  List<HistoryEntry> loadHistory() => _loadEntries(_historySlot);

  /// Saves the navigation history.
  ///
  /// Automatically trims to [maxHistoryEntries].
  Future<void> saveHistory(List<HistoryEntry> entries) async {
    await _saveEntries(_historySlot, entries);
  }

  /// Loads the user's favorite locations.
  List<HistoryEntry> loadFavorites() => _loadEntries(_favoritesSlot);

  /// Saves the user's favorite locations.
  ///
  /// Capped at [maxFavoriteEntries] to prevent unbounded storage growth.
  Future<void> saveFavorites(List<HistoryEntry> favorites) async {
    await _saveEntries(_favoritesSlot, favorites);
  }

  /// Adds an entry to favorites.
  Future<void> addFavorite(HistoryEntry entry) async {
    final favorites = loadFavorites();
    // Check if already exists by ID
    if (favorites.any((f) => f.id == entry.id)) return;
    favorites.add(entry);
    await saveFavorites(favorites);
  }

  /// Removes an entry from favorites by ID.
  Future<void> removeFavorite(String entryId) async {
    final favorites = loadFavorites();
    final updated = favorites.where((f) => f.id != entryId).toList();
    await saveFavorites(updated);
  }

  /// Clears all navigation history.
  Future<void> clearHistory() async {
    await _prefs.remove(_historyKey);
  }

  /// Clears all favorites.
  Future<void> clearFavorites() async {
    await _prefs.remove(_favoritesKey);
  }

  List<HistoryEntry> _loadEntries(_HistoryStoreSlot slot) {
    final payload = _prefs.getString(slot.key);
    return _HistoryEntryCodec.parse(payload, slotLabel: slot.label);
  }

  Future<void> _saveEntries(
    _HistoryStoreSlot slot,
    List<HistoryEntry> entries,
  ) async {
    final bounded = slot.mostRecent(entries);
    await _prefs.setString(slot.key, _HistoryEntryCodec.serialize(bounded));
  }
}

const _historySlot = _HistoryStoreSlot(
  key: HistoryStore._historyKey,
  label: 'history',
  maxEntries: HistoryStore.maxHistoryEntries,
);

const _favoritesSlot = _HistoryStoreSlot(
  key: HistoryStore._favoritesKey,
  label: 'favorites',
  maxEntries: HistoryStore.maxFavoriteEntries,
);

/// Storage contract for one SharedPreferences-backed history collection.
///
/// Entries are expected oldest-first. When a slot exceeds its cap, the oldest
/// entries are dropped and the most recent tail is retained.
class _HistoryStoreSlot {
  final String key;
  final String label;
  final int maxEntries;

  const _HistoryStoreSlot({
    required this.key,
    required this.label,
    required this.maxEntries,
  }) : assert(maxEntries > 0);

  List<HistoryEntry> mostRecent(List<HistoryEntry> entries) {
    if (entries.length <= maxEntries) return entries;
    return entries.sublist(entries.length - maxEntries);
  }
}

class _HistoryEntryCodec {
  const _HistoryEntryCodec._();

  static List<HistoryEntry> parse(String? payload,
      {required String slotLabel}) {
    if (payload == null || payload.isEmpty) return [];
    try {
      final decoded = jsonDecode(payload) as List;
      final entries = <HistoryEntry>[];
      for (final item in decoded) {
        try {
          final entry =
              HistoryEntry.fromJson((item as Map).cast<String, Object?>());
          entries.add(entry);
        } catch (e) {
          // Skip corrupted entry, continue with others.
          if (kDebugMode) {
            debugPrint('Failed to parse $slotLabel entry: $e');
          }
        }
      }
      return entries;
    } catch (e) {
      // Corrupted JSON, return empty list.
      if (kDebugMode) debugPrint('Failed to parse $slotLabel JSON: $e');
      return [];
    }
  }

  static String serialize(List<HistoryEntry> entries) {
    return jsonEncode(entries.map((e) => e.toJson()).toList());
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:vector_math/vector_math.dart';
import 'package:flutter_fractals/core/services/history_store.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';

HistoryEntry _makeEntry(String id, {String moduleId = 'mandelbrot'}) {
  return HistoryEntry(
    id: id,
    moduleId: moduleId,
    view: FractalViewState(
      pan: Vector2(0.0, 0.0),
      zoom: 1.0,
      rotation: Vector3.zero(),
    ),
    params: {},
    visitedAt: DateTime.utc(2024, 1, 1),
  );
}

void main() {
  group('HistoryStore', () {
    setUp(() {
      TestWidgetsFlutterBinding.ensureInitialized();
      SharedPreferences.setMockInitialValues({});
    });

    test('create() factory returns a valid store', () async {
      final store = await HistoryStore.create();
      expect(store, isNotNull);
    });

    test('loadHistory returns empty list when no data stored', () async {
      final store = await HistoryStore.create();
      expect(store.loadHistory(), isEmpty);
    });

    test('saveHistory and loadHistory round-trip entries', () async {
      final store = await HistoryStore.create();
      final entries = [
        _makeEntry('1', moduleId: 'mandelbrot'),
        _makeEntry('2', moduleId: 'julia'),
      ];

      await store.saveHistory(entries);
      final loaded = store.loadHistory();

      expect(loaded, hasLength(2));
      expect(loaded[0].id, equals('1'));
      expect(loaded[0].moduleId, equals('mandelbrot'));
      expect(loaded[1].id, equals('2'));
      expect(loaded[1].moduleId, equals('julia'));
    });

    test('history entries maintain insertion order', () async {
      final store = await HistoryStore.create();
      final entries = [
        _makeEntry('first', moduleId: 'mandelbrot'),
        _makeEntry('second', moduleId: 'julia'),
        _makeEntry('third', moduleId: 'burning_ship'),
      ];

      await store.saveHistory(entries);
      final loaded = store.loadHistory();

      expect(loaded, hasLength(3));
      expect(loaded[0].id, equals('first'));
      expect(loaded[1].id, equals('second'));
      expect(loaded[2].id, equals('third'));
    });

    test('saveHistory caps oldest-first history to most recent entries',
        () async {
      final store = await HistoryStore.create();
      final entries = [
        for (var i = 0; i < HistoryStore.maxHistoryEntries + 2; i++)
          _makeEntry('history_$i'),
      ];

      await store.saveHistory(entries);
      final loaded = store.loadHistory();

      expect(loaded, hasLength(HistoryStore.maxHistoryEntries));
      expect(loaded.first.id, 'history_2');
      expect(loaded.last.id, 'history_${HistoryStore.maxHistoryEntries + 1}');
    });

    test('loadFavorites returns empty list when no data stored', () async {
      final store = await HistoryStore.create();
      expect(store.loadFavorites(), isEmpty);
    });

    test('addFavorite appends entry to favorites', () async {
      final store = await HistoryStore.create();
      final entry = _makeEntry('fav1');

      await store.addFavorite(entry);
      final favorites = store.loadFavorites();

      expect(favorites, hasLength(1));
      expect(favorites.first.id, equals('fav1'));
    });

    test('addFavorite does not duplicate existing entry', () async {
      final store = await HistoryStore.create();
      final entry = _makeEntry('fav1');

      await store.addFavorite(entry);
      await store.addFavorite(entry);
      final favorites = store.loadFavorites();

      expect(favorites, hasLength(1));
    });

    test('saveFavorites caps oldest-first favorites to most recent entries',
        () async {
      final store = await HistoryStore.create();
      final entries = [
        for (var i = 0; i < HistoryStore.maxFavoriteEntries + 2; i++)
          _makeEntry('favorite_$i'),
      ];

      await store.saveFavorites(entries);
      final loaded = store.loadFavorites();

      expect(loaded, hasLength(HistoryStore.maxFavoriteEntries));
      expect(loaded.first.id, 'favorite_2');
      expect(loaded.last.id, 'favorite_${HistoryStore.maxFavoriteEntries + 1}');
    });

    test('removeFavorite removes entry by ID', () async {
      final store = await HistoryStore.create();
      await store.addFavorite(_makeEntry('fav1'));
      await store.addFavorite(_makeEntry('fav2'));

      await store.removeFavorite('fav1');
      final favorites = store.loadFavorites();

      expect(favorites, hasLength(1));
      expect(favorites.first.id, equals('fav2'));
    });

    test('clearHistory removes all history', () async {
      final store = await HistoryStore.create();
      await store.saveHistory([_makeEntry('1'), _makeEntry('2')]);

      await store.clearHistory();
      expect(store.loadHistory(), isEmpty);
    });

    test('loadHistory handles corrupted JSON gracefully', () async {
      SharedPreferences.setMockInitialValues({
        'exploration_history': 'not valid json {{{',
      });
      final store = await HistoryStore.create();
      expect(store.loadHistory(), isEmpty);
    });

    test('loadHistory skips corrupted individual entries', () async {
      // Valid JSON array but one entry has missing required fields.
      SharedPreferences.setMockInitialValues({
        'exploration_history':
            '[{"id":"1","moduleId":"mandelbrot","view":{"panX":0,"panY":0,"zoom":1,"rotX":0,"rotY":0,"rotZ":0},"params":{},"visitedAt":"2024-01-01T00:00:00.000Z"},{"bad":"entry"}]',
      });
      final store = await HistoryStore.create();
      final loaded = store.loadHistory();
      // The valid entry should be present; the corrupted one silently skipped.
      expect(loaded, hasLength(1));
      expect(loaded.first.id, equals('1'));
    });
  });
}

import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:vector_math/vector_math.dart';
import 'fractal_view_state.dart';

/// A saved configuration of fractal parameters and view state.
///
/// Presets allow users to save and restore specific fractal configurations,
/// including both the mathematical parameters (iterations, bailout, etc.)
/// and the view state (pan, zoom, rotation).
///
/// Presets can be:
/// - **Built-in**: Included with the app and read-only
/// - **User-created**: Saved by the user with custom thumbnails
///
/// Presets are serializable to JSON for persistent storage.
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final preset = FractalPreset(
///   id: 'my-preset',
///   moduleId: 'mandelbrot',
///   name: 'Deep Zoom',
///   params: {'iterations': 200, 'colorScheme': 2},
///   view: FractalViewState(
///     pan: Vector2(-0.75, 0.1),
///     zoom: 50.0,
///     rotation: Vector3.zero(),
///   ),
///   createdAt: DateTime.now(),
/// );
/// ```
@immutable
class FractalPreset {
  /// Unique identifier for this preset.
  ///
  /// For built-in presets, use a pattern like 'module-name'.
  /// For user presets, typically a UUID.
  final String id;

  /// The fractal module this preset belongs to.
  ///
  /// Must match a [FractalModule.id] in the registry.
  /// Presets are only applicable to their target module.
  final String moduleId;

  /// User-visible name for this preset.
  ///
  /// Should be descriptive and unique within the module's presets.
  final String name;

  /// The fractal parameter values.
  ///
  /// Keys are parameter IDs (e.g., 'iterations', 'colorScheme').
  /// Values are typed according to [FractalParamType].
  final Map<String, Object> params;

  /// The view state (pan, zoom, rotation) for this preset.
  ///
  /// Defines the camera position and orientation when
  /// the preset is applied.
  final FractalViewState view;

  /// When this preset was created.
  ///
  /// Used for sorting and display purposes.
  final DateTime createdAt;

  /// Whether this is a built-in (read-only) preset.
  ///
  /// Built-in presets cannot be edited or deleted by the user.
  final bool isBuiltIn;

  /// Path to the preset's thumbnail image.
  ///
  /// For user presets, this is typically a file path to a
  /// captured PNG. Built-in presets may use asset paths.
  final String? thumbnailPath;

  /// Creates a new [FractalPreset] with the specified configuration.
  const FractalPreset({
    required this.id,
    required this.moduleId,
    required this.name,
    required this.params,
    required this.view,
    required this.createdAt,
    this.isBuiltIn = false,
    this.thumbnailPath,
  });

  /// Creates a copy of this preset with the given fields replaced.
  ///
  /// Useful for creating variations of existing presets. Because `null` means
  /// "keep the existing value" for optional fields, set [clearThumbnailPath]
  /// when a copy must remove an existing thumbnail.
  FractalPreset copyWith({
    String? id,
    String? moduleId,
    String? name,
    Map<String, Object>? params,
    FractalViewState? view,
    DateTime? createdAt,
    bool? isBuiltIn,
    String? thumbnailPath,
    bool clearThumbnailPath = false,
  }) {
    assert(
      !clearThumbnailPath || thumbnailPath == null,
      'thumbnailPath cannot be provided when clearThumbnailPath is true',
    );
    return FractalPreset(
      id: id ?? this.id,
      moduleId: moduleId ?? this.moduleId,
      name: name ?? this.name,
      params: params ?? this.params,
      view: view ?? this.view,
      createdAt: createdAt ?? this.createdAt,
      isBuiltIn: isBuiltIn ?? this.isBuiltIn,
      thumbnailPath:
          clearThumbnailPath ? null : thumbnailPath ?? this.thumbnailPath,
    );
  }

  /// Serializes this preset to a JSON-compatible map.
  ///
  /// Used for persistent storage in SharedPreferences.
  Map<String, Object?> toJson() {
    return {
      'id': id,
      'moduleId': moduleId,
      'name': name,
      'params': params,
      'view': {
        'panX': view.pan.x,
        'panY': view.pan.y,
        'zoom': view.zoom,
        'rotX': view.rotation.x,
        'rotY': view.rotation.y,
        'rotZ': view.rotation.z,
      },
      'createdAt': createdAt.toIso8601String(),
      'isBuiltIn': isBuiltIn,
      'thumbnailPath': thumbnailPath,
    };
  }

  /// Deserializes a preset from a JSON map.
  ///
  /// Throws if required fields are missing.
  static FractalPreset fromJson(Map<String, Object?> json) {
    final view = json['view'] as Map<String, Object?>? ?? {};
    return FractalPreset(
      id: json['id'] as String,
      moduleId: json['moduleId'] as String,
      name: json['name'] as String,
      params: (json['params'] as Map)
          .map((key, value) => MapEntry(key as String, value as Object)),
      view: FractalViewState(
        pan: Vector2(
          (view['panX'] as num? ?? 0).toDouble(),
          (view['panY'] as num? ?? 0).toDouble(),
        ),
        zoom: (view['zoom'] as num? ?? 1).toDouble(),
        rotation: Vector3(
          (view['rotX'] as num? ?? 0).toDouble(),
          (view['rotY'] as num? ?? 0).toDouble(),
          (view['rotZ'] as num? ?? 0).toDouble(),
        ),
      ),
      createdAt: DateTime.tryParse(json['createdAt'] as String? ?? '') ??
          DateTime.now(),
      isBuiltIn: json['isBuiltIn'] as bool? ?? false,
      thumbnailPath: json['thumbnailPath'] as String?,
    );
  }

  /// Parses a list of presets from a JSON string.
  ///
  /// Returns an empty list if [payload] is null or empty.
  /// Skips corrupted entries and continues parsing valid ones.
  /// Used for reading from SharedPreferences.
  static List<FractalPreset> listFromPrefs(String? payload) {
    if (payload == null || payload.isEmpty) {
      return [];
    }
    try {
      final decoded = jsonDecode(payload) as List;
      final presets = <FractalPreset>[];
      for (final item in decoded) {
        try {
          final preset =
              FractalPreset.fromJson((item as Map).cast<String, Object?>());
          presets.add(preset);
        } catch (e) {
          // Skip corrupted preset, continue with others
          if (kDebugMode) debugPrint('Failed to parse preset: $e');
        }
      }
      return presets;
    } catch (e) {
      // Corrupted JSON, return empty list
      if (kDebugMode) debugPrint('Failed to parse presets JSON: $e');
      return [];
    }
  }

  /// Serializes a list of presets to a JSON string.
  ///
  /// Used for writing to SharedPreferences.
  static String listToPrefs(List<FractalPreset> presets) {
    return jsonEncode(presets.map((preset) => preset.toJson()).toList());
  }
}

import 'dart:collection';
import 'dart:math' as math;
import 'package:flutter/foundation.dart';
import 'package:flutter/scheduler.dart';
import 'package:flutter_fractals/core/services/app_logger_service.dart';

/// Performance metrics collected during rendering.
///
/// Contains frame timing, shader compilation, and memory usage data.
@immutable
class PerformanceMetrics {
  /// Average frame time in milliseconds.
  final double avgFrameTimeMs;

  /// Minimum frame time in milliseconds.
  final double minFrameTimeMs;

  /// Maximum frame time in milliseconds.
  final double maxFrameTimeMs;

  /// 95th percentile frame time in milliseconds.
  final double p95FrameTimeMs;

  /// 99th percentile frame time in milliseconds.
  final double p99FrameTimeMs;

  /// Number of frames rendered.
  final int frameCount;

  /// Number of dropped frames (> 16.67ms).
  final int droppedFrames;

  /// Current frames per second.
  final double fps;

  /// Number of shader compilations detected.
  final int shaderCompilations;

  /// Memory usage in megabytes (if available).
  final double? memoryUsageMb;

  /// Peak memory usage in megabytes.
  final double? peakMemoryMb;

  /// Whether the app is currently experiencing jank.
  final bool isJanky;

  /// Total profiling duration in seconds.
  final double durationSeconds;

  /// Frame time stability score (0-100, 100 = perfectly stable).
  final double stabilityScore;

  const PerformanceMetrics({
    required this.avgFrameTimeMs,
    required this.minFrameTimeMs,
    required this.maxFrameTimeMs,
    required this.p95FrameTimeMs,
    required this.p99FrameTimeMs,
    required this.frameCount,
    required this.droppedFrames,
    required this.fps,
    required this.shaderCompilations,
    this.memoryUsageMb,
    this.peakMemoryMb,
    this.isJanky = false,
    required this.durationSeconds,
    required this.stabilityScore,
  });

  /// Creates empty metrics.
  const PerformanceMetrics.empty()
      : avgFrameTimeMs = 0,
        minFrameTimeMs = 0,
        maxFrameTimeMs = 0,
        p95FrameTimeMs = 0,
        p99FrameTimeMs = 0,
        frameCount = 0,
        droppedFrames = 0,
        fps = 0,
        shaderCompilations = 0,
        memoryUsageMb = null,
        peakMemoryMb = null,
        isJanky = false,
        durationSeconds = 0,
        stabilityScore = 100;

  /// Frame drop percentage (0-100).
  double get dropPercentage => frameCount > 0 ? (droppedFrames / frameCount) * 100 : 0;

  /// Whether performance is considered good (> 55 FPS, < 5% drops).
  bool get isGood => fps >= 55 && dropPercentage < 5;

  /// Whether performance is acceptable (> 30 FPS, < 15% drops).
  bool get isAcceptable => fps >= 30 && dropPercentage < 15;

  @override
  String toString() => 'PerformanceMetrics(fps: ${fps.toStringAsFixed(1)}, '
      'avg: ${avgFrameTimeMs.toStringAsFixed(2)}ms, '
      'dropped: $droppedFrames/$frameCount)';
}

/// A single frame timing sample.
@immutable
class FrameSample {
  final Duration timestamp;
  final double frameTimeMs;
  final bool wasDropped;
  final bool hadShaderCompile;

  const FrameSample({
    required this.timestamp,
    required this.frameTimeMs,
    required this.wasDropped,
    this.hadShaderCompile = false,
  });
}

/// Service for collecting and analyzing rendering performance.
///
/// Tracks frame times, detects shader compilation stalls, and monitors
/// memory usage to provide real-time performance metrics.
class PerformanceService extends ChangeNotifier {
  static const int _maxSamples = 300; // ~5 seconds at 60fps
  static const double _targetFrameTime = 16.67; // 60 FPS
  static const double _shaderStallThreshold = 100.0; // 100ms suggests compilation

  final Queue<FrameSample> _samples = Queue();
  Ticker? _ticker;
  Duration _lastFrameTime = Duration.zero;
  Stopwatch? _sessionStopwatch;

  bool _isRunning = false;
  int _shaderCompilations = 0;
  double _peakMemoryMb = 0;
  PerformanceMetrics _currentMetrics = const PerformanceMetrics.empty();

  /// Whether performance tracking is currently active.
  bool get isRunning => _isRunning;

  /// Current performance metrics.
  PerformanceMetrics get metrics => _currentMetrics;

  /// Most recent frame samples for graphing.
  List<FrameSample> get samples => _samples.toList();

  /// Starts performance tracking.
  ///
  /// Attaches to the scheduler's ticker to measure frame times.
  void start(TickerProvider vsync) {
    if (_isRunning) return;

    _isRunning = true;
    _samples.clear();
    _shaderCompilations = 0;
    _peakMemoryMb = 0;
    _lastFrameTime = Duration.zero;
    _sessionStopwatch = Stopwatch()..start();

    _ticker = vsync.createTicker(_onTick);
    _ticker!.start();

    notifyListeners();
  }

  /// Stops performance tracking.
  void stop() {
    if (!_isRunning) return;

    _ticker?.stop();
    _ticker?.dispose();
    _ticker = null;
    _sessionStopwatch?.stop();
    _isRunning = false;

    _updateMetrics();
    notifyListeners();
  }

  /// Resets all collected metrics.
  void reset() {
    _samples.clear();
    _shaderCompilations = 0;
    _peakMemoryMb = 0;
    _currentMetrics = const PerformanceMetrics.empty();
    _sessionStopwatch?.reset();
    if (_isRunning) {
      _sessionStopwatch?.start();
    }
    notifyListeners();
  }

  void _onTick(Duration elapsed) {
    if (_lastFrameTime == Duration.zero) {
      _lastFrameTime = elapsed;
      return;
    }

    final frameTimeMs = (elapsed - _lastFrameTime).inMicroseconds / 1000.0;
    _lastFrameTime = elapsed;

    // Detect shader compilation stalls
    final hadShaderCompile = frameTimeMs > _shaderStallThreshold;
    if (hadShaderCompile) {
      _shaderCompilations++;
    }

    final sample = FrameSample(
      timestamp: elapsed,
      frameTimeMs: frameTimeMs,
      wasDropped: frameTimeMs > _targetFrameTime,
      hadShaderCompile: hadShaderCompile,
    );

    _samples.addLast(sample);
    if (_samples.length > _maxSamples) {
      _samples.removeFirst();
    }

    // Update memory tracking periodically
    if (_samples.length % 30 == 0) {
      _updateMemoryUsage();
    }

    // Update metrics every ~0.5 seconds (30 frames)
    if (_samples.length % 30 == 0) {
      _updateMetrics();
      notifyListeners();
    }

    // Log performance snapshot every ~1 second (60 frames) — sampled to avoid noise
    if (_samples.length % 60 == 0) {
      _logPerformanceSnapshot();
    }
  }

  /// Logs a concise FPS/frame-time snapshot via [AppLogger].
  void _logPerformanceSnapshot() {
    final m = _currentMetrics;
    if (m.frameCount == 0) return;
    AppLogger.instance.debug('perf', 'fps_snapshot', data: {
      'fps': m.fps.toStringAsFixed(1),
      'avg_ms': m.avgFrameTimeMs.toStringAsFixed(2),
      'p95_ms': m.p95FrameTimeMs.toStringAsFixed(2),
      'dropped': m.droppedFrames,
      'frames': m.frameCount,
    });
  }

  void _updateMemoryUsage() {
    // Note: In Flutter, getting exact memory usage requires platform channels
    // or debug mode APIs. This is a simplified approach using heuristics.
    // For accurate memory profiling, use DevTools or platform-specific APIs.

    // Placeholder: In real app, use PlatformDispatcher.instance.onReportTimings
    // or implement platform channels for memory stats
  }

  void _updateMetrics() {
    if (_samples.isEmpty) {
      _currentMetrics = const PerformanceMetrics.empty();
      return;
    }

    final frameTimes = _samples.map((s) => s.frameTimeMs).toList();
    frameTimes.sort();

    final avg = frameTimes.reduce((a, b) => a + b) / frameTimes.length;
    final min = frameTimes.first;
    final max = frameTimes.last;

    // Calculate percentiles
    final p95Index = (frameTimes.length * 0.95).floor().clamp(0, frameTimes.length - 1);
    final p99Index = (frameTimes.length * 0.99).floor().clamp(0, frameTimes.length - 1);
    final p95 = frameTimes[p95Index];
    final p99 = frameTimes[p99Index];

    // Count dropped frames
    final droppedFrames = _samples.where((s) => s.wasDropped).length;

    // Calculate FPS from average frame time
    final fps = avg > 0 ? 1000.0 / avg : 0.0;

    // Calculate stability score (based on variance)
    final variance = frameTimes.map((t) => (t - avg) * (t - avg)).reduce((a, b) => a + b) / frameTimes.length;
    final stdDev = variance > 0 ? variance.sqrt() : 0;
    final stabilityScore = (100 - (stdDev / _targetFrameTime * 100)).clamp(0.0, 100.0);

    // Check for current jank (recent frames)
    final recentSamples = _samples.toList().reversed.take(10);
    final recentDrops = recentSamples.where((s) => s.wasDropped).length;
    final isJanky = recentDrops > 3;

    final durationSeconds = (_sessionStopwatch?.elapsedMilliseconds ?? 0) / 1000.0;

    _currentMetrics = PerformanceMetrics(
      avgFrameTimeMs: avg,
      minFrameTimeMs: min,
      maxFrameTimeMs: max,
      p95FrameTimeMs: p95,
      p99FrameTimeMs: p99,
      frameCount: _samples.length,
      droppedFrames: droppedFrames,
      fps: fps,
      shaderCompilations: _shaderCompilations,
      memoryUsageMb: null, // Platform-specific
      peakMemoryMb: _peakMemoryMb > 0 ? _peakMemoryMb : null,
      isJanky: isJanky,
      durationSeconds: durationSeconds,
      stabilityScore: stabilityScore,
    );
  }

  /// Gets a formatted summary of the current performance.
  String getSummary() {
    final m = _currentMetrics;
    final buffer = StringBuffer();

    buffer.writeln('=== Performance Summary ===');
    buffer.writeln('Duration: ${m.durationSeconds.toStringAsFixed(1)}s');
    buffer.writeln('FPS: ${m.fps.toStringAsFixed(1)} (${_getFpsRating(m.fps)})');
    buffer.writeln('Frame Time: ${m.avgFrameTimeMs.toStringAsFixed(2)}ms avg');
    buffer.writeln('  Min: ${m.minFrameTimeMs.toStringAsFixed(2)}ms');
    buffer.writeln('  Max: ${m.maxFrameTimeMs.toStringAsFixed(2)}ms');
    buffer.writeln('  P95: ${m.p95FrameTimeMs.toStringAsFixed(2)}ms');
    buffer.writeln('  P99: ${m.p99FrameTimeMs.toStringAsFixed(2)}ms');
    buffer.writeln('Dropped Frames: ${m.droppedFrames}/${m.frameCount} (${m.dropPercentage.toStringAsFixed(1)}%)');
    buffer.writeln('Shader Compilations: ${m.shaderCompilations}');
    buffer.writeln('Stability Score: ${m.stabilityScore.toStringAsFixed(0)}/100');

    return buffer.toString();
  }

  String _getFpsRating(double fps) {
    if (fps >= 58) return 'Excellent';
    if (fps >= 50) return 'Good';
    if (fps >= 30) return 'Acceptable';
    return 'Poor';
  }

  @override
  void dispose() {
    stop();
    super.dispose();
  }
}

/// Extension for calculating square root on doubles.
extension DoubleExtension on double {
  double sqrt() => this >= 0 ? math.sqrt(this) : 0;
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/services/performance_service.dart';

void main() {
  group('PerformanceMetrics', () {
    test('empty metrics have default values', () {
      const metrics = PerformanceMetrics.empty();

      expect(metrics.avgFrameTimeMs, 0);
      expect(metrics.fps, 0);
      expect(metrics.frameCount, 0);
      expect(metrics.droppedFrames, 0);
      expect(metrics.stabilityScore, 100);
      expect(metrics.isJanky, false);
    });

    test('calculates drop percentage correctly', () {
      const metrics = PerformanceMetrics(
        avgFrameTimeMs: 16.67,
        minFrameTimeMs: 15.0,
        maxFrameTimeMs: 20.0,
        p95FrameTimeMs: 18.0,
        p99FrameTimeMs: 19.0,
        frameCount: 100,
        droppedFrames: 10,
        fps: 60,
        shaderCompilations: 0,
        durationSeconds: 1.67,
        stabilityScore: 90,
      );

      expect(metrics.dropPercentage, 10.0);
    });

    test('isGood returns true for excellent performance', () {
      const metrics = PerformanceMetrics(
        avgFrameTimeMs: 16.0,
        minFrameTimeMs: 15.0,
        maxFrameTimeMs: 17.0,
        p95FrameTimeMs: 16.5,
        p99FrameTimeMs: 17.0,
        frameCount: 100,
        droppedFrames: 3,
        fps: 60,
        shaderCompilations: 0,
        durationSeconds: 1.67,
        stabilityScore: 95,
      );

      expect(metrics.isGood, true);
      expect(metrics.isAcceptable, true);
    });

    test('isGood returns false for poor performance', () {
      const metrics = PerformanceMetrics(
        avgFrameTimeMs: 40.0,
        minFrameTimeMs: 30.0,
        maxFrameTimeMs: 80.0,
        p95FrameTimeMs: 60.0,
        p99FrameTimeMs: 75.0,
        frameCount: 100,
        droppedFrames: 50,
        fps: 25,
        shaderCompilations: 2,
        durationSeconds: 4.0,
        stabilityScore: 40,
      );

      expect(metrics.isGood, false);
      expect(metrics.isAcceptable, false);
    });

    test('isAcceptable returns true for moderate performance', () {
      const metrics = PerformanceMetrics(
        avgFrameTimeMs: 25.0,
        minFrameTimeMs: 20.0,
        maxFrameTimeMs: 35.0,
        p95FrameTimeMs: 30.0,
        p99FrameTimeMs: 33.0,
        frameCount: 100,
        droppedFrames: 12,
        fps: 40,
        shaderCompilations: 1,
        durationSeconds: 2.5,
        stabilityScore: 75,
      );

      expect(metrics.isGood, false);
      expect(metrics.isAcceptable, true);
    });
  });

  group('FrameSample', () {
    test('creates sample with correct values', () {
      const sample = FrameSample(
        timestamp: Duration(milliseconds: 1000),
        frameTimeMs: 16.67,
        wasDropped: false,
        hadShaderCompile: false,
      );

      expect(sample.timestamp.inMilliseconds, 1000);
      expect(sample.frameTimeMs, 16.67);
      expect(sample.wasDropped, false);
      expect(sample.hadShaderCompile, false);
    });

    test('identifies dropped frames', () {
      const sample = FrameSample(
        timestamp: Duration(milliseconds: 1000),
        frameTimeMs: 33.34,
        wasDropped: true,
        hadShaderCompile: false,
      );

      expect(sample.wasDropped, true);
    });

    test('identifies shader compilation stalls', () {
      const sample = FrameSample(
        timestamp: Duration(milliseconds: 1000),
        frameTimeMs: 150.0,
        wasDropped: true,
        hadShaderCompile: true,
      );

      expect(sample.hadShaderCompile, true);
    });
  });

  group('PerformanceService', () {
    test('starts in stopped state', () {
      final service = PerformanceService();

      expect(service.isRunning, false);
      expect(service.metrics.frameCount, 0);
      expect(service.samples, isEmpty);
    });

    test('reset clears all data', () {
      final service = PerformanceService();

      // Add some dummy state (if we could run it)
      service.reset();

      expect(service.samples, isEmpty);
      expect(service.metrics.frameCount, 0);
      expect(service.metrics.shaderCompilations, 0);
    });

    test('getSummary returns formatted string', () {
      final service = PerformanceService();
      final summary = service.getSummary();

      expect(summary, contains('Performance Summary'));
      expect(summary, contains('FPS:'));
      expect(summary, contains('Frame Time:'));
      expect(summary, contains('Dropped Frames:'));
    });

    test('disposes cleanly', () {
      final service = PerformanceService();

      // Should not throw
      expect(() => service.dispose(), returnsNormally);
    });
  });

  group('DoubleExtension', () {
    test('sqrt works for positive numbers', () {
      expect(4.0.sqrt(), closeTo(2.0, 0.001));
      expect(9.0.sqrt(), closeTo(3.0, 0.001));
      expect(16.0.sqrt(), closeTo(4.0, 0.001));
    });

    test('sqrt returns 0 for negative numbers', () {
      expect((-4.0).sqrt(), 0);
      expect((-1.0).sqrt(), 0);
    });

    test('sqrt of zero is zero', () {
      expect(0.0.sqrt(), 0);
    });
  });
}

import 'dart:io';

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/services/renderer_settings_service.dart';

const bool kForceCpuFallback =
    bool.fromEnvironment('FORCE_CPU_FALLBACK', defaultValue: false);
// Android emulator GPU is allowed in auto mode. Runtime health probes in
// FractalViewerScreen enforce fast fallback to CPU on invalid output.

enum RendererBackend { gpu, cpu }

enum FallbackReasonCode {
  none,
  forcedByFlag,
  androidEmulator,
  gpuHealthCheckFailed,
  deepZoomPrecision,
  manualToggle,
  moduleUnsupported,
}

class BackendDecision {
  final RendererBackend backend;
  final FallbackReasonCode reasonCode;
  final String detail;

  const BackendDecision({
    required this.backend,
    required this.reasonCode,
    required this.detail,
  });

  bool get isFallback => backend == RendererBackend.cpu;

  String get reasonToken {
    switch (reasonCode) {
      case FallbackReasonCode.none:
        return 'none';
      case FallbackReasonCode.forcedByFlag:
        return 'forced_by_flag';
      case FallbackReasonCode.androidEmulator:
        return 'android_emulator';
      case FallbackReasonCode.gpuHealthCheckFailed:
        return 'gpu_health_check_failed';
      case FallbackReasonCode.deepZoomPrecision:
        return 'deep_zoom_precision';
      case FallbackReasonCode.manualToggle:
        return 'manual_toggle';
      case FallbackReasonCode.moduleUnsupported:
        return 'module_unsupported';
    }
  }

  String toLogLine({required String moduleId}) {
    return '[renderer] backend_decision backend=${backend.name} reason=$reasonToken module=$moduleId detail=$detail';
  }

  String toUserStatusText() {
    if (!isFallback) return 'Renderer: GPU';
    switch (reasonCode) {
      case FallbackReasonCode.androidEmulator:
        return 'Using stable renderer for this Android emulator';
      case FallbackReasonCode.gpuHealthCheckFailed:
        return 'GPU output unavailable, using stable renderer';
      case FallbackReasonCode.deepZoomPrecision:
        return 'Deep zoom precision mode enabled';
      case FallbackReasonCode.manualToggle:
        return 'Renderer preference applied';
      case FallbackReasonCode.moduleUnsupported:
        return 'Stable renderer enabled for this fractal mode';
      case FallbackReasonCode.forcedByFlag:
        return 'Stable renderer forced by launch flag';
      case FallbackReasonCode.none:
        return 'Renderer: CPU';
    }
  }
}

class BackendPolicyInput {
  final bool isAndroid;
  final bool isWeb;
  final bool isEmulator;
  final RendererBackendMode userMode;
  final bool gpuHealthFailed;
  final bool deepZoomNeedsCpu;
  final FractalDimension dimension;

  const BackendPolicyInput({
    required this.isAndroid,
    required this.isWeb,
    required this.isEmulator,
    required this.userMode,
    required this.gpuHealthFailed,
    required this.deepZoomNeedsCpu,
    required this.dimension,
  });
}

/// Replayable explanation for the backend rule selected by the policy.
///
/// Platform probes are currently advisory in auto mode: Android emulator status
/// is logged and passed through, but runtime health checks decide fallback.
/// Keeping the selected rule visible makes that precedence testable instead of
/// hiding it in early returns.
class BackendPolicyResolution {
  final BackendDecision decision;
  final String selectedRule;
  final bool platformSignalsUsed;

  const BackendPolicyResolution({
    required this.decision,
    required this.selectedRule,
    required this.platformSignalsUsed,
  });
}

class RendererBackendPolicy {
  const RendererBackendPolicy();

  BackendDecision decide(BackendPolicyInput input) => explain(input).decision;

  BackendPolicyResolution explain(BackendPolicyInput input) {
    if (kForceCpuFallback) {
      return const BackendPolicyResolution(
        selectedRule: 'force_cpu_flag',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.forcedByFlag,
          detail: 'FORCE_CPU_FALLBACK=true',
        ),
      );
    }

    if (input.dimension != FractalDimension.twoD) {
      // 3D modules (e.g. Mandelbulb/Mandelbox) currently rely on GPU shader
      // rendering. Forcing CPU here only produces a disabled placeholder pane.
      // Keep these modules on GPU by default.
      if (input.userMode == RendererBackendMode.cpuOnly) {
        return const BackendPolicyResolution(
          selectedRule: 'gpu_required_module_cpu_only_ignored',
          platformSignalsUsed: false,
          decision: BackendDecision(
            backend: RendererBackend.gpu,
            reasonCode: FallbackReasonCode.moduleUnsupported,
            detail: 'cpu_only_ignored_for_3d_gpu_required',
          ),
        );
      }
      return const BackendPolicyResolution(
        selectedRule: 'gpu_required_module',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.gpu,
          reasonCode: FallbackReasonCode.none,
          detail: '3d_gpu_path',
        ),
      );
    }

    if (input.userMode == RendererBackendMode.cpuOnly) {
      return const BackendPolicyResolution(
        selectedRule: 'manual_cpu_only',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.manualToggle,
          detail: 'cpu_only',
        ),
      );
    }

    if (input.userMode == RendererBackendMode.gpuOnly) {
      return const BackendPolicyResolution(
        selectedRule: 'manual_gpu_only',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.gpu,
          reasonCode: FallbackReasonCode.manualToggle,
          detail: 'gpu_only',
        ),
      );
    }

    // Emulator targets are handled like physical devices in auto mode.
    // Runtime GPU health checks own fallback decisions.

    if (input.gpuHealthFailed) {
      return const BackendPolicyResolution(
        selectedRule: 'gpu_health_failed',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.gpuHealthCheckFailed,
          detail: 'frame_probe_detected_invalid_gpu_output',
        ),
      );
    }

    if (input.deepZoomNeedsCpu) {
      return const BackendPolicyResolution(
        selectedRule: 'deep_zoom_precision',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.deepZoomPrecision,
          detail: 'deep_zoom_precision_policy',
        ),
      );
    }

    return const BackendPolicyResolution(
      selectedRule: 'healthy_gpu_target',
      platformSignalsUsed: false,
      decision: BackendDecision(
        backend: RendererBackend.gpu,
        reasonCode: FallbackReasonCode.none,
        detail: 'healthy_gpu_target',
      ),
    );
  }
}

/// Replayable Android emulator signal snapshot.
///
/// Device probing is intentionally best-effort and IO-heavy; keeping the
/// signal classifier pure makes marker drift testable without touching
/// `/proc`, `getprop`, or `/system` in unit tests.
class AndroidEmulatorSignals {
  final String cpuInfo;
  final String hardware;
  final String buildCharacteristics;
  final String productModel;
  final String buildProp;

  const AndroidEmulatorSignals({
    this.cpuInfo = '',
    this.hardware = '',
    this.buildCharacteristics = '',
    this.productModel = '',
    this.buildProp = '',
  });

  bool get isEmulator =>
      AndroidEmulatorMarkerCatalog.hasCpuInfoMarker(cpuInfo) ||
      AndroidEmulatorMarkerCatalog.hasHardwareMarker(hardware) ||
      AndroidEmulatorMarkerCatalog.hasBuildCharacteristicsMarker(
        buildCharacteristics,
      ) ||
      AndroidEmulatorMarkerCatalog.hasProductModelMarker(productModel) ||
      AndroidEmulatorMarkerCatalog.hasBuildPropMarker(buildProp);
}

/// Named emulator marker contract used by Android emulator signal detection.
///
/// The markers are intentionally conservative: substring checks are used only
/// for fields that can contain labels or full property files, while the direct
/// `ro.hardware` value must match a known virtual hardware token exactly.
class AndroidEmulatorMarkerCatalog {
  static const List<String> cpuInfoSubstrings = [
    'ranchu',
    'goldfish',
    'qemu',
    'android virtual processor',
  ];
  static const List<String> exactHardwareValues = ['ranchu', 'goldfish'];
  static const List<String> buildCharacteristicsSubstrings = ['emulator'];
  static const List<String> productModelSubstrings = [
    'sdk_gphone',
    'android sdk built for',
  ];
  static const List<String> buildPropSubstrings = [
    'ro.hardware=goldfish',
    'ro.hardware=ranchu',
    'sdk_gphone',
    'generic_x86',
  ];

  const AndroidEmulatorMarkerCatalog._();

  static bool hasCpuInfoMarker(String value) {
    return _containsAny(value, cpuInfoSubstrings);
  }

  static bool hasHardwareMarker(String value) {
    return exactHardwareValues.contains(value.trim().toLowerCase());
  }

  static bool hasBuildCharacteristicsMarker(String value) {
    return _containsAny(value, buildCharacteristicsSubstrings);
  }

  static bool hasProductModelMarker(String value) {
    return _containsAny(value, productModelSubstrings);
  }

  static bool hasBuildPropMarker(String value) {
    return _containsAny(value, buildPropSubstrings);
  }

  static bool _containsAny(String value, List<String> markers) {
    final normalized = value.toLowerCase();
    return markers.any(normalized.contains);
  }
}

Future<bool> detectAndroidEmulator() async {
  if (kIsWeb || !Platform.isAndroid) return false;

  var signals = const AndroidEmulatorSignals();

  // 1. /proc/cpuinfo — check for emulator markers
  try {
    signals = AndroidEmulatorSignals(
      cpuInfo: await File('/proc/cpuinfo').readAsString(),
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  // 2. getprop — most reliable on modern emulators
  try {
    final result = await Process.run('getprop', ['ro.hardware']);
    signals = AndroidEmulatorSignals(hardware: result.stdout as String);
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  try {
    final result = await Process.run('getprop', ['ro.build.characteristics']);
    signals = AndroidEmulatorSignals(
      buildCharacteristics: result.stdout as String,
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  try {
    final result = await Process.run('getprop', ['ro.product.model']);
    signals = AndroidEmulatorSignals(productModel: result.stdout as String);
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  // 3. /system/build.prop — fallback file check
  try {
    signals = AndroidEmulatorSignals(
      buildProp: await File('/system/build.prop').readAsString(),
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  return false;
}

import 'dart:math' as math;

import 'package:flutter/foundation.dart';

const double _mandelbrotDf2LowerThreshold = 5e6;
const double _mandelbrotDf2UpperThreshold = 1e12;
const double _escapeTimeCpuFallbackThreshold = 1e9;
const double _defaultCpuFallbackThreshold = 1e7;

/// Describes the precision boundaries for one fractal module.
@immutable
class DeepZoomThresholds {
  final double cpuFallbackZoom;
  final double? doubleFloatLowerZoom;
  final double? doubleFloatUpperZoom;

  const DeepZoomThresholds({
    required this.cpuFallbackZoom,
    this.doubleFloatLowerZoom,
    this.doubleFloatUpperZoom,
  })  : assert(
          (doubleFloatLowerZoom == null) == (doubleFloatUpperZoom == null),
          'double-float ranges must provide both lower and upper bounds',
        ),
        assert(
          (doubleFloatLowerZoom ?? double.negativeInfinity) <
              (doubleFloatUpperZoom ?? double.infinity),
          'double-float lower bound must be below upper bound',
        ),
        assert(
          (doubleFloatUpperZoom ?? double.negativeInfinity) <= cpuFallbackZoom,
          'double-float range must end no later than CPU fallback',
        );

  bool get supportsDoubleFloat => doubleFloatLowerZoom != null;

  bool shouldUseCpuFallback(double zoom) => zoom >= cpuFallbackZoom;

  bool shouldUseDoubleFloat(double zoom) {
    final lower = doubleFloatLowerZoom;
    final upper = doubleFloatUpperZoom;
    if (lower == null || upper == null) return false;
    return zoom >= lower && zoom < upper;
  }
}

/// Replayable precision routing decision for a module/zoom sample.
///
/// Renderer code needs CPU fallback and double-float eligibility to agree on
/// the same threshold snapshot. Keeping both booleans with their source
/// thresholds exposes that data-flow instead of recomputing partial decisions
/// at separate call sites.
@immutable
class DeepZoomPrecisionDecision {
  final String moduleId;
  final double zoom;
  final DeepZoomThresholds thresholds;

  const DeepZoomPrecisionDecision({
    required this.moduleId,
    required this.zoom,
    required this.thresholds,
  });

  bool get shouldUseCpuFallback => thresholds.shouldUseCpuFallback(zoom);
  bool get shouldUseDoubleFloat => thresholds.shouldUseDoubleFloat(zoom);
  double get cpuFallbackZoom => thresholds.cpuFallbackZoom;
}

/// Decides when GPU precision is likely insufficient at deep zoom.
///
/// ## Float32 precision analysis
///
/// GPU fragment shaders use float32 arithmetic (~7 significant digits,
/// mantissa ≈ 2^-24 ≈ 6e-8).
///
/// The coordinate span per pixel is: span_per_px = fractal_range / (zoom * resolution)
///   For a 1080p display and a fractal range of ~3 units:
///     span_per_px = 3 / (zoom * 1920) ≈ 1.6e-3 / zoom
///
/// Float32 artifacts appear when the per-pixel span drops below the
/// representable precision at the current center offset. In the worst case
/// (center near origin, no cancellation) this is roughly:
///     artifact threshold zoom ≈ 1.6e-3 / 6e-8 ≈ 2.7e4  ... but only at
///     an offset of ~1.0 unit from origin. Deep in the Mandelbrot boundary
///     where |c| ≈ 2, precision is consumed faster (≈ 1e4–1e5).
///     With the standard center at (0,0) or a well-normalized fractal,
///     artifacts are not visible until zoom ≈ 1e6–1e8.
///
/// Our shaders perform double-width emulation via paired float32 values
/// (see shader uniform layout) for a subset of fractals, extending usable
/// GPU range to ~1e12 before requiring CPU.
///
/// ## Conservative threshold policy
///
/// These thresholds are intentionally HIGH so GPU is used as long as
/// possible. The CPU fallback is a correctness escape hatch, not a
/// performance choice — it is significantly slower and disables GPU effects.
///
/// Raise these thresholds if you observe visible precision artifacts before
/// the switch; lower them only if tested on a low-DPI device where artifacts
/// appear earlier.
@immutable
class DeepZoomPrecisionPolicy {
  /// Maximum iterations we send to GPU shaders for real-time rendering.
  ///
  /// Most escape-time shaders clamp around this value already; keeping the
  /// cap centralized avoids overdriving slower devices at extreme zoom.
  static const int gpuMaxIterations = 2000;

  /// Per-module GPU→CPU fallback thresholds.
  ///
  /// For mandelbrot, the CPU fallback threshold is pushed to the df2 upper
  /// bound because the double-float shader [mandelbrot_df2.frag] covers the
  /// intermediate zoom range before CPU fallback.
  ///
  /// Other escape-time fractals still use float32 GPU up to their threshold,
  /// then fall back to CPU (no df2 variant available yet).
  static const Map<String, DeepZoomThresholds> _moduleThresholds = {
    // Mandelbrot: df2 shader covers zoom [5e6, 1e12), so CPU fallback only
    // kicks in at 1e12 (the df2 upper bound).
    'mandelbrot': DeepZoomThresholds(
      cpuFallbackZoom: _mandelbrotDf2UpperThreshold,
      doubleFloatLowerZoom: _mandelbrotDf2LowerThreshold,
      doubleFloatUpperZoom: _mandelbrotDf2UpperThreshold,
    ),
    // Julia & related escape-time fractals: GPU precision degrades sooner,
    // so switch to CPU around ~1e9.
    'julia': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'celtic': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'buffalo': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'burning_ship': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'tricorn': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot3': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot4': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot5': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'phoenix': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
  };

  /// Default threshold for any fractal type not listed above.
  /// Simple orbit fractals and non-escape-time types lose precision more
  /// slowly; 1e7 is a conservative upper bound for float32 at 1080p.
  static const DeepZoomThresholds _defaultThresholds = DeepZoomThresholds(
    cpuFallbackZoom: _defaultCpuFallbackThreshold,
  );

  /// Number of consecutive evaluations above the zoom threshold required
  /// before committing to CPU fallback. Prevents rapid GPU↔CPU flicker
  /// when zooming near the boundary.
  static const int _hysteresisFrames = 2;

  const DeepZoomPrecisionPolicy();

  /// Returns true when GPU precision is insufficient at the given zoom.
  ///
  /// Pure, stateless evaluation — callers that want hysteresis should
  /// use [DeepZoomHysteresis] to track frame counts.
  bool shouldUseCpuFallback({
    required String moduleId,
    required double zoom,
  }) {
    return decisionFor(moduleId: moduleId, zoom: zoom).shouldUseCpuFallback;
  }

  DeepZoomThresholds thresholdsFor(String moduleId) =>
      _moduleThresholds[moduleId] ?? _defaultThresholds;

  DeepZoomPrecisionDecision decisionFor({
    required String moduleId,
    required double zoom,
  }) {
    return DeepZoomPrecisionDecision(
      moduleId: moduleId,
      zoom: zoom,
      thresholds: thresholdsFor(moduleId),
    );
  }

  double thresholdFor(String moduleId) =>
      thresholdsFor(moduleId).cpuFallbackZoom;

  /// Returns true when the double-float shader should be used for [moduleId].
  ///
  /// Currently only mandelbrot has a df2 variant. The range is exclusive of
  /// the CPU fallback threshold.
  bool shouldUseDoubleFloat({
    required String moduleId,
    required double zoom,
  }) {
    return decisionFor(moduleId: moduleId, zoom: zoom).shouldUseDoubleFloat;
  }

  int get hysteresisFrames => _hysteresisFrames;

  /// Auto-scales iteration count with zoom depth for GPU rendering.
  ///
  /// Keeps shallow zoom responsive while increasing detail as zoom grows,
  /// reducing under-iteration artifacts in deep zoom.
  ///
  /// Scaling curve:
  /// - zoom <= 1: unchanged
  /// - zoom > 1: base * (1 + 0.35 * log10(zoom))
  /// - clamped to [4, gpuMaxIterations]
  int scaledGpuIterations({
    required int baseIterations,
    required double zoom,
  }) {
    final safeBase = baseIterations.clamp(4, gpuMaxIterations);
    final depth = _zoomDepthLog10(zoom);
    if (depth == 0.0) return safeBase;

    final factor = 1.0 + 0.35 * depth;
    final scaled = (safeBase * factor).round();
    return scaled.clamp(4, gpuMaxIterations);
  }
}

double _zoomDepthLog10(double zoom) {
  if (zoom.isNaN || zoom <= 1.0) return 0.0;
  if (zoom.isInfinite) return 30.0;
  return (math.log(zoom) / math.ln10).clamp(0.0, 30.0);
}

/// Replayable state for one GPU→CPU deep-zoom hysteresis streak.
///
/// Keeping the transition pure makes the hidden state/order dependence visible:
/// streaks are scoped to one module, below-threshold samples reset immediately,
/// and CPU fallback activates only after enough consecutive above-threshold
/// samples for the same module.
@immutable
class DeepZoomHysteresisState {
  final String? moduleId;
  final int aboveThresholdCount;
  final bool cpuActive;

  const DeepZoomHysteresisState({
    required this.moduleId,
    required this.aboveThresholdCount,
    required this.cpuActive,
  });

  const DeepZoomHysteresisState.initial()
      : moduleId = null,
        aboveThresholdCount = 0,
        cpuActive = false;

  DeepZoomHysteresisState next({
    required String nextModuleId,
    required bool overThreshold,
    required int activationFrames,
  }) {
    assert(activationFrames > 0, 'activationFrames must be positive');
    final sameModule = moduleId == nextModuleId;
    final currentCount = sameModule ? aboveThresholdCount : 0;

    if (!overThreshold) {
      return DeepZoomHysteresisState(
        moduleId: nextModuleId,
        aboveThresholdCount: 0,
        cpuActive: false,
      );
    }

    final nextCount = currentCount + 1;
    return DeepZoomHysteresisState(
      moduleId: nextModuleId,
      aboveThresholdCount: nextCount,
      cpuActive: nextCount >= activationFrames,
    );
  }
}

/// Stateful hysteresis filter for GPU→CPU deep-zoom transitions.
///
/// Wraps [DeepZoomPrecisionPolicy] and requires [policy.hysteresisFrames]
/// consecutive above-threshold evaluations before reporting CPU needed.
/// Drops back to GPU immediately when zoom falls below threshold.
class DeepZoomHysteresis {
  final DeepZoomPrecisionPolicy policy;
  DeepZoomHysteresisState _state = const DeepZoomHysteresisState.initial();

  DeepZoomHysteresis({this.policy = const DeepZoomPrecisionPolicy()});

  DeepZoomHysteresisState get state => _state;

  /// Call this on every zoom change. Returns true if CPU fallback is warranted.
  bool update({required String moduleId, required double zoom}) {
    final overThreshold = policy.shouldUseCpuFallback(
      moduleId: moduleId,
      zoom: zoom,
    );

    _state = _state.next(
      nextModuleId: moduleId,
      overThreshold: overThreshold,
      activationFrames: policy.hysteresisFrames,
    );
    return _state.cpuActive;
  }

  void reset() {
    _state = const DeepZoomHysteresisState.initial();
  }
}

import 'dart:typed_data';

import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/services/renderer_settings_service.dart';
import 'package:flutter_fractals/features/renderer/backend_policy.dart';
import 'package:flutter_fractals/features/renderer/render_validation.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('RendererBackendPolicy', () {
    const policy = RendererBackendPolicy();

    test('prefers GPU on healthy target', () {
      final decision = policy.decide(
        const BackendPolicyInput(
          isAndroid: false,
          isWeb: false,
          isEmulator: false,
          userMode: RendererBackendMode.auto,
          gpuHealthFailed: false,
          deepZoomNeedsCpu: false,
          dimension: FractalDimension.twoD,
        ),
      );

      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.none);
    });

    test('uses GPU on healthy android emulator in auto mode', () {
      final decision = policy.decide(
        const BackendPolicyInput(
          isAndroid: true,
          isWeb: false,
          isEmulator: true,
          userMode: RendererBackendMode.auto,
          gpuHealthFailed: false,
          deepZoomNeedsCpu: false,
          dimension: FractalDimension.twoD,
        ),
      );

      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.none);
    });

    test('falls back to CPU on android emulator when GPU health fails', () {
      final decision = policy.decide(
        const BackendPolicyInput(
          isAndroid: true,
          isWeb: false,
          isEmulator: true,
          userMode: RendererBackendMode.auto,
          gpuHealthFailed: true,
          deepZoomNeedsCpu: false,
          dimension: FractalDimension.twoD,
        ),
      );

      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
      expect(decision.reasonToken, 'gpu_health_check_failed');
    });

    test('keeps 3D modules on GPU in auto mode', () {
      final decision = policy.decide(
        const BackendPolicyInput(
          isAndroid: true,
          isWeb: false,
          isEmulator: false,
          userMode: RendererBackendMode.auto,
          gpuHealthFailed: true,
          deepZoomNeedsCpu: false,
          dimension: FractalDimension.threeD,
        ),
      );

      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.none);
    });
  });

  group('Render validation', () {
    test('detects non-black histogram and progression', () {
      final frameA = Uint8List.fromList(List<int>.filled(16 * 4, 0));
      final frameB = Uint8List.fromList(List<int>.filled(16 * 4, 0));

      // center pixel (1,1) for a 4x4 image
      const center = (1 * 4 + 1) * 4;
      frameB[center] = 64;
      frameB[center + 1] = 96;
      frameB[center + 2] = 128;

      // add additional non-black + changed pixels
      for (int i = 0; i < frameB.length; i += 8) {
        frameB[i] = 32;
        frameB[i + 1] = 16;
        frameB[i + 2] = 48;
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );

      expect(result.centerNonBlack, isTrue);
      expect(result.histogramSane, isTrue);
      expect(result.frameProgressed, isTrue);
      expect(result.iterationDeltaVisible, isTrue);
    });
  });
}

import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/services/renderer_settings_service.dart';
import 'package:flutter_fractals/features/renderer/backend_policy.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  const policy = RendererBackendPolicy();

  // Helper to build a standard 2D auto input with overrides.
  BackendPolicyInput buildInput({
    bool isAndroid = false,
    bool isWeb = false,
    bool isEmulator = false,
    RendererBackendMode userMode = RendererBackendMode.auto,
    bool gpuHealthFailed = false,
    bool deepZoomNeedsCpu = false,
    FractalDimension dimension = FractalDimension.twoD,
  }) {
    return BackendPolicyInput(
      isAndroid: isAndroid,
      isWeb: isWeb,
      isEmulator: isEmulator,
      userMode: userMode,
      gpuHealthFailed: gpuHealthFailed,
      deepZoomNeedsCpu: deepZoomNeedsCpu,
      dimension: dimension,
    );
  }

  group('cpuOnly user mode', () {
    test('cpuOnly always returns cpu backend for 2D', () {
      final decision =
          policy.decide(buildInput(userMode: RendererBackendMode.cpuOnly));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('cpuOnly on non-emulator non-android still returns cpu', () {
      final decision = policy.decide(buildInput(
        isAndroid: false,
        isEmulator: false,
        userMode: RendererBackendMode.cpuOnly,
      ));
      expect(decision.backend, RendererBackend.cpu);
    });

    test('cpuOnly with gpuHealthFailed still returns cpu via manualToggle', () {
      // cpuOnly is evaluated before health-check; reason should be manualToggle
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        gpuHealthFailed: true,
      ));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('cpuOnly is ignored for 3D module — GPU required', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        dimension: FractalDimension.threeD,
      ));
      // 3D always uses GPU; cpuOnly is overridden
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.moduleUnsupported);
    });
  });

  group('gpuOnly user mode', () {
    test('gpuOnly always returns gpu backend for 2D', () {
      final decision =
          policy.decide(buildInput(userMode: RendererBackendMode.gpuOnly));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('gpuOnly bypasses deep-zoom CPU fallback', () {
      // gpuOnly is evaluated before deepZoomNeedsCpu check
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.gpuOnly,
        deepZoomNeedsCpu: true,
      ));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('gpuOnly bypasses GPU health check', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.gpuOnly,
        gpuHealthFailed: true,
      ));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });
  });

  group('deep zoom CPU fallback', () {
    test('deepZoomNeedsCpu triggers cpu backend in auto mode', () {
      final decision = policy.decide(buildInput(deepZoomNeedsCpu: true));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.deepZoomPrecision);
    });

    test('deepZoomNeedsCpu reasonToken is deep_zoom_precision', () {
      final decision = policy.decide(buildInput(deepZoomNeedsCpu: true));
      expect(decision.reasonToken, 'deep_zoom_precision');
    });

    test('deepZoomNeedsCpu is evaluated after gpuHealthFailed', () {
      // gpuHealthFailed is checked first in the policy
      final decision = policy.decide(buildInput(
        gpuHealthFailed: true,
        deepZoomNeedsCpu: true,
      ));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
    });
  });

  group('GPU health failure', () {
    test('GPU health failure in auto mode returns cpu', () {
      final decision = policy.decide(buildInput(gpuHealthFailed: true));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
    });

    test('combined emulator + GPU health fail returns cpu', () {
      final decision = policy.decide(buildInput(
        isAndroid: true,
        isEmulator: true,
        gpuHealthFailed: true,
      ));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
    });

    test('isFallback is true when backend is cpu', () {
      final decision = policy.decide(buildInput(gpuHealthFailed: true));
      expect(decision.isFallback, isTrue);
    });
  });

  group('policy explanation', () {
    test('exposes selected rule while preserving decide compatibility', () {
      final resolution = policy.explain(buildInput(gpuHealthFailed: true));

      expect(resolution.selectedRule, 'gpu_health_failed');
      expect(resolution.platformSignalsUsed, isFalse);
      expect(resolution.decision.backend, RendererBackend.cpu);
      expect(policy.decide(buildInput(gpuHealthFailed: true)).reasonCode,
          resolution.decision.reasonCode);
    });

    test('documents platform signals as advisory in auto mode', () {
      final emulatorResolution = policy.explain(buildInput(
        isAndroid: true,
        isEmulator: true,
      ));
      final webResolution = policy.explain(buildInput(isWeb: true));

      expect(emulatorResolution.selectedRule, 'healthy_gpu_target');
      expect(emulatorResolution.platformSignalsUsed, isFalse);
      expect(webResolution.selectedRule, 'healthy_gpu_target');
      expect(webResolution.platformSignalsUsed, isFalse);
    });
  });

  group('healthy GPU with auto mode', () {
    test('healthy GPU with auto mode returns gpu', () {
      final decision = policy.decide(buildInput());
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.none);
    });

    test('isFallback is false for gpu decision', () {
      final decision = policy.decide(buildInput());
      expect(decision.isFallback, isFalse);
    });

    test('reasonToken is none for healthy GPU', () {
      final decision = policy.decide(buildInput());
      expect(decision.reasonToken, 'none');
    });

    test('toUserStatusText returns GPU label on healthy path', () {
      final decision = policy.decide(buildInput());
      expect(decision.toUserStatusText(), 'Renderer: GPU');
    });
  });

  group('3D module (unsupported GPU override)', () {
    test('3D module with auto mode uses GPU', () {
      final decision =
          policy.decide(buildInput(dimension: FractalDimension.threeD));
      expect(decision.backend, RendererBackend.gpu);
    });

    test('cpuOnly is ignored for 3D — moduleUnsupported reason', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        dimension: FractalDimension.threeD,
      ));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.moduleUnsupported);
      expect(decision.reasonToken, 'module_unsupported');
    });

    test('3D module toUserStatusText returns GPU label (backend is gpu)', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        dimension: FractalDimension.threeD,
      ));
      // backend == gpu so isFallback is false; toUserStatusText returns 'Renderer: GPU'
      // regardless of reasonCode because the !isFallback check fires first.
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.isFallback, isFalse);
      expect(decision.toUserStatusText(), 'Renderer: GPU');
    });
  });

  group('AndroidEmulatorSignals', () {
    test('classifies each emulator marker without IO', () {
      const samples = [
        AndroidEmulatorSignals(cpuInfo: 'Hardware\t: ranchu'),
        AndroidEmulatorSignals(
            cpuInfo: 'Processor\t: Android Virtual Processor'),
        AndroidEmulatorSignals(cpuInfo: 'vendor_id\t: QEMU'),
        AndroidEmulatorSignals(hardware: ' goldfish\n'),
        AndroidEmulatorSignals(buildCharacteristics: 'nosdcard,emulator'),
        AndroidEmulatorSignals(productModel: 'sdk_gphone64_x86_64'),
        AndroidEmulatorSignals(productModel: 'Android SDK built for x86'),
        AndroidEmulatorSignals(buildProp: 'ro.hardware=ranchu\n'),
        AndroidEmulatorSignals(buildProp: 'ro.product.cpu.abi=generic_x86'),
      ];

      for (final sample in samples) {
        expect(sample.isEmulator, isTrue);
      }
    });

    test('does not classify physical-device-looking signals as emulator', () {
      const signals = AndroidEmulatorSignals(
        cpuInfo: 'Hardware\t: Qualcomm Technologies',
        hardware: 'qcom',
        buildCharacteristics: 'default',
        productModel: 'Pixel 8',
        buildProp: 'ro.hardware=qcom\nro.product.model=Pixel 8\n',
      );

      expect(signals.isEmulator, isFalse);
    });
  });

  group('BackendDecision helpers', () {
    test('toLogLine contains backend, reason, module, and detail', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.deepZoomPrecision,
        detail: 'deep_zoom_precision_policy',
      );
      final line = decision.toLogLine(moduleId: 'mandelbrot');
      expect(line, contains('backend=cpu'));
      expect(line, contains('reason=deep_zoom_precision'));
      expect(line, contains('module=mandelbrot'));
      expect(line, contains('detail=deep_zoom_precision_policy'));
    });

    test('toUserStatusText for deep zoom precision', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.deepZoomPrecision,
        detail: '',
      );
      expect(decision.toUserStatusText(), 'Deep zoom precision mode enabled');
    });

    test('toUserStatusText for manual toggle cpu', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.manualToggle,
        detail: 'cpu_only',
      );
      expect(decision.toUserStatusText(), 'Renderer preference applied');
    });

    test('toUserStatusText for forced by flag', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.forcedByFlag,
        detail: '',
      );
      expect(
          decision.toUserStatusText(), 'Stable renderer forced by launch flag');
    });
  });
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/features/renderer/deep_zoom_precision_policy.dart';

void main() {
  const policy = DeepZoomPrecisionPolicy();

  group('DeepZoomPrecisionPolicy.thresholdsFor', () {
    test('exposes contiguous Mandelbrot df2 to CPU fallback boundaries', () {
      final thresholds = policy.thresholdsFor('mandelbrot');

      expect(thresholds.supportsDoubleFloat, isTrue);
      expect(thresholds.doubleFloatLowerZoom, 5e6);
      expect(thresholds.doubleFloatUpperZoom, thresholds.cpuFallbackZoom);
      expect(thresholds.shouldUseDoubleFloat(1e11), isTrue);
      expect(
        thresholds.shouldUseDoubleFloat(thresholds.cpuFallbackZoom),
        isFalse,
      );
      expect(
        thresholds.shouldUseCpuFallback(thresholds.cpuFallbackZoom),
        isTrue,
      );
    });

    test('exposes default thresholds without a double-float range', () {
      final thresholds = policy.thresholdsFor('unknown_fractal');

      expect(thresholds.cpuFallbackZoom, 1e7);
      expect(thresholds.supportsDoubleFloat, isFalse);
      expect(thresholds.shouldUseDoubleFloat(1e10), isFalse);
    });
  });

  group('DeepZoomPrecisionPolicy.decisionFor', () {
    test('exposes CPU and double-float routing from one threshold snapshot',
        () {
      final decision = policy.decisionFor(moduleId: 'mandelbrot', zoom: 1e10);

      expect(decision.moduleId, 'mandelbrot');
      expect(decision.zoom, 1e10);
      expect(decision.cpuFallbackZoom, 1e12);
      expect(decision.shouldUseDoubleFloat, isTrue);
      expect(decision.shouldUseCpuFallback, isFalse);
      expect(decision.thresholds, same(policy.thresholdsFor('mandelbrot')));
    });

    test('keeps invalid zoom samples below precision routing thresholds', () {
      for (final zoom in [double.nan, double.negativeInfinity]) {
        final decision = policy.decisionFor(
          moduleId: 'mandelbrot',
          zoom: zoom,
        );

        expect(decision.shouldUseDoubleFloat, isFalse, reason: '$zoom');
        expect(decision.shouldUseCpuFallback, isFalse, reason: '$zoom');
      }
    });
  });

  group('DeepZoomPrecisionPolicy.shouldUseCpuFallback', () {
    test('returns false for mandelbrot at zoom 1e6', () {
      expect(
        policy.shouldUseCpuFallback(moduleId: 'mandelbrot', zoom: 1e6),
        isFalse,
      );
    });

    test('returns true for mandelbrot at zoom 1e15', () {
      expect(
        policy.shouldUseCpuFallback(moduleId: 'mandelbrot', zoom: 1e15),
        isTrue,
      );
    });

    test('uses default threshold for unknown module', () {
      // Default threshold is 1e7; zoom just below should be false.
      expect(
        policy.shouldUseCpuFallback(moduleId: 'unknown_fractal', zoom: 9.9e6),
        isFalse,
      );
      // At or above default threshold (1e7) should be true.
      expect(
        policy.shouldUseCpuFallback(moduleId: 'unknown_fractal', zoom: 1e7),
        isTrue,
      );
    });
  });

  group('DeepZoomPrecisionPolicy.shouldUseDoubleFloat', () {
    test('returns true for mandelbrot in df2 range', () {
      // df2 range: [5e6, 1e12)
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 5e6),
        isTrue,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e10),
        isTrue,
      );
    });

    test('returns false for non-mandelbrot modules', () {
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'julia', zoom: 1e10),
        isFalse,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'burning_ship', zoom: 1e10),
        isFalse,
      );
    });

    test('returns false below df2 lower threshold', () {
      // Below 5e6 the standard float32 shader is sufficient.
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e5),
        isFalse,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 4.9e6),
        isFalse,
      );
    });

    test('returns false at or above df2 upper threshold', () {
      // At 1e12 CPU fallback takes over; df2 should not be active.
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e12),
        isFalse,
      );
    });
  });

  group('DeepZoomPrecisionPolicy.scaledGpuIterations', () {
    test('returns base at zoom 1', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: 1.0),
        equals(256),
      );
    });

    test('returns base at zoom below 1', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: 0.5),
        equals(256),
      );
    });

    test('increases with zoom depth', () {
      final atZoom1 =
          policy.scaledGpuIterations(baseIterations: 256, zoom: 1.0);
      final atZoom1e6 =
          policy.scaledGpuIterations(baseIterations: 256, zoom: 1e6);
      expect(atZoom1e6, greaterThan(atZoom1));
    });

    test('clamps to gpuMaxIterations', () {
      // Very high base + very high zoom should be clamped.
      final result = policy.scaledGpuIterations(
        baseIterations: DeepZoomPrecisionPolicy.gpuMaxIterations,
        zoom: 1e30,
      );
      expect(result, equals(DeepZoomPrecisionPolicy.gpuMaxIterations));
    });

    test('clamps low base to minimum of 4', () {
      final result = policy.scaledGpuIterations(baseIterations: 1, zoom: 1.0);
      expect(result, equals(4));
    });

    test('treats non-finite zoom values as bounded inputs', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: double.nan),
        equals(256),
      );
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: double.infinity),
        equals(DeepZoomPrecisionPolicy.gpuMaxIterations),
      );
      expect(
        policy.scaledGpuIterations(
          baseIterations: 256,
          zoom: double.negativeInfinity,
        ),
        equals(256),
      );
    });
  });

  group('DeepZoomHysteresisState', () {
    test('exposes replayable streak transitions', () {
      const initial = DeepZoomHysteresisState.initial();

      final first = initial.next(
        nextModuleId: 'julia',
        overThreshold: true,
        activationFrames: 2,
      );
      final second = first.next(
        nextModuleId: 'julia',
        overThreshold: true,
        activationFrames: 2,
      );
      final resetByZoomOut = second.next(
        nextModuleId: 'julia',
        overThreshold: false,
        activationFrames: 2,
      );
      final resetByModule = first.next(
        nextModuleId: 'mandelbrot',
        overThreshold: true,
        activationFrames: 2,
      );

      expect(first.moduleId, 'julia');
      expect(first.aboveThresholdCount, 1);
      expect(first.cpuActive, isFalse);
      expect(second.aboveThresholdCount, 2);
      expect(second.cpuActive, isTrue);
      expect(resetByZoomOut.aboveThresholdCount, 0);
      expect(resetByZoomOut.cpuActive, isFalse);
      expect(resetByModule.moduleId, 'mandelbrot');
      expect(resetByModule.aboveThresholdCount, 1);
      expect(resetByModule.cpuActive, isFalse);
    });
  });

  group('DeepZoomHysteresis', () {
    test('does not activate CPU until hysteresisFrames consecutive frames', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      // mandelbrot CPU threshold is 1e12; zoom 2e12 is above it.
      const moduleId = 'mandelbrot';
      const highZoom = 2e12;
      final frames = policy.hysteresisFrames;

      // All frames before the last should still return false.
      for (var i = 0; i < frames - 1; i++) {
        expect(
          hysteresis.update(moduleId: moduleId, zoom: highZoom),
          isFalse,
          reason: 'frame $i should not activate CPU yet',
        );
      }

      // The hysteresisFrames-th frame should activate.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: highZoom),
        isTrue,
      );
    });

    test('drops back to GPU immediately when zoom falls below threshold', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      const moduleId = 'mandelbrot';
      const highZoom = 2e14;
      const lowZoom = 1.0;
      final frames = policy.hysteresisFrames;

      // Trigger CPU mode.
      for (var i = 0; i < frames; i++) {
        hysteresis.update(moduleId: moduleId, zoom: highZoom);
      }

      // A single below-threshold update drops back to GPU.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: lowZoom),
        isFalse,
      );
    });

    test('does not carry above-threshold count across module changes', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);

      expect(
        hysteresis.update(moduleId: 'julia', zoom: 2e9),
        isFalse,
        reason: 'first Julia deep-zoom frame should only prime hysteresis',
      );

      expect(
        hysteresis.update(moduleId: 'mandelbrot', zoom: 2e14),
        isFalse,
        reason: 'first Mandelbrot deep-zoom frame must not inherit Julia count',
      );

      expect(
        hysteresis.update(moduleId: 'mandelbrot', zoom: 2e14),
        isTrue,
        reason: 'second consecutive Mandelbrot deep-zoom frame activates CPU',
      );
    });

    test('reset clears state so hysteresis counter restarts', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      const moduleId = 'mandelbrot';
      const highZoom = 2e14;
      final frames = policy.hysteresisFrames;

      // Build up to just before activation.
      for (var i = 0; i < frames - 1; i++) {
        hysteresis.update(moduleId: moduleId, zoom: highZoom);
      }

      hysteresis.reset();

      // After reset, the counter is zero; a single update should not activate.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: highZoom),
        isFalse,
      );
    });
  });
}

import 'dart:typed_data';

import 'package:flutter_fractals/features/renderer/cpu_fractal_renderer.dart';
