import 'package:fake_async/fake_async.dart';
import 'package:flutter_fractals/features/catalog/catalog_search_debouncer.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('CatalogSearchDebouncer', () {
    test('only fires the latest scheduled callback', () {
      fakeAsync((async) {
        final fired = <String>[];
        final debouncer = CatalogSearchDebouncer(
          delay: const Duration(milliseconds: 300),
        );

        debouncer.schedule(() => fired.add('first'));
        async.elapse(const Duration(milliseconds: 150));
        debouncer.schedule(() => fired.add('second'));

        async.elapse(const Duration(milliseconds: 149));
        expect(fired, isEmpty);

        async.elapse(const Duration(milliseconds: 151));
        expect(fired, ['second']);
      });
    });

    test('cancel drops a pending callback', () {
      fakeAsync((async) {
        var fired = false;
        final debouncer = CatalogSearchDebouncer(
          delay: const Duration(milliseconds: 300),
        );

        debouncer.schedule(() => fired = true);
        debouncer.cancel();
        async.elapse(const Duration(milliseconds: 300));

        expect(fired, isFalse);
      });
    });
  });
}

